{
  "name": "Nile Fleet Invoice Management",
  "description": "A comprehensive invoice generation system for logistics companies, featuring automated grouping by booking number, multiple invoice themes, and custom company branding.",
  "requestFramePermissions": []
}

export interface BookingRow {
  Customer: string;
  BookingNo: string;
  UnitNumber: string;
  PortGo: string;
  PortGi: string;
  Trucker: string;
  Shipper: string;
  Rate: number;
  Date: string;
}

export interface CustomerSettings {
  name: string;
  dueDateDays: number;
  serialPrefix: string;
  startingSerial: number;
}

export interface CompanyInfo {
  name: string;
  address: string;
  email: string;
  phone: string;
  logo: string | null;
  signature: string | null;
  watermark: string | null;
}

export type InvoiceTheme = 
  | 'minimal' 
  | 'corporate' 
  | 'elegant' 
  | 'bold' 
  | 'dark' 
  | 'grid' 
  | 'classic' 
  | 'soft' 
  | 'industrial' 
  | 'compact';

export interface Invoice {
  id: string;
  bookingNo: string;
  customer: string;
  date: string;
  dueDate: string;
  serialNumber: string;
  items: BookingRow[];
  total: number;
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useMemo, useEffect } from 'react';
import { 
  FileText, 
  Users, 
  Settings, 
  Plus, 
  Download, 
  Printer, 
  Eye, 
  Trash2,
  FileSpreadsheet,
  Building2,
  Info
} from 'lucide-react';
import { BookingRow, CustomerSettings, CompanyInfo, Invoice, InvoiceTheme } from './types';
import { INITIAL_CSV_DATA, THEMES } from './constants';
import BookingScreen from './components/BookingScreen';
import CustomerScreen from './components/CustomerScreen';
import InfoScreen from './components/InfoScreen';
import InvoiceModal from './components/InvoiceModal';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'bookings' | 'customers' | 'info'>('bookings');
  const [bookings, setBookings] = useState<BookingRow[]>([]);
  const [customerSettings, setCustomerSettings] = useState<Record<string, CustomerSettings>>({});
  const [companyInfo, setCompanyInfo] = useState<CompanyInfo>({
    name: 'NILE FLEET',
    address: '123 Cairo Logistics Hub, Nile Delta, Egypt',
    email: 'billing@nilefleet.com',
    phone: '+20 123 456 7890',
    logo: null,
    signature: null,
    watermark: null
  });

  const [selectedInvoice, setSelectedInvoice] = useState<Invoice | null>(null);
  const [selectedTheme, setSelectedTheme] = useState<InvoiceTheme>('minimal');

  // Parse Initial Data
  useEffect(() => {
    const lines = INITIAL_CSV_DATA.split('\n');
    const headers = lines[0].split(',');
    const parsed: BookingRow[] = lines.slice(1).filter(l => l.trim()).map(line => {
      const values = line.split(',');
      return {
        Customer: values[0],
        BookingNo: values[1],
        UnitNumber: values[2],
        PortGo: values[3],
        PortGi: values[4],
        Trucker: values[5],
        Shipper: values[6],
        Rate: parseFloat(values[7]),
        Date: values[8]
      };
    });
    setBookings(parsed);

    // Auto-detect customers
    const uniqueCustomers = Array.from(new Set(parsed.map(p => p.Customer)));
    const initialSettings: Record<string, CustomerSettings> = {};
    uniqueCustomers.forEach((c, idx) => {
      initialSettings[c] = {
        name: c,
        dueDateDays: 15,
        serialPrefix: 'INV-2026-',
        startingSerial: 100 + idx
      };
    });
    setCustomerSettings(initialSettings);
  }, []);

  // Group Bookings into Invoices
  const invoices = useMemo(() => {
    const groups: Record<string, BookingRow[]> = {};
    bookings.forEach(row => {
      if (!groups[row.BookingNo]) groups[row.BookingNo] = [];
      groups[row.BookingNo].push(row);
    });

    return Object.entries(groups).map(([bookingNo, items], index) => {
      const customerName = items[0].Customer;
      const settings = customerSettings[customerName];
      const serialNum = settings 
        ? `${settings.serialPrefix}${settings.startingSerial + index}`
        : `INV-${bookingNo}`;

      const date = new Date(items[0].Date);
      const dueDate = new Date(date);
      dueDate.setDate(date.getDate() + (settings?.dueDateDays || 15));

      return {
        id: bookingNo,
        bookingNo,
        customer: customerName,
        date: items[0].Date,
        dueDate: dueDate.toISOString().split('T')[0],
        serialNumber: serialNum,
        items,
        total: items.reduce((sum, item) => sum + item.Rate, 0)
      } as Invoice;
    });
  }, [bookings, customerSettings]);

  const handleUpdateCustomer = (name: string, settings: CustomerSettings) => {
    setCustomerSettings(prev => ({ ...prev, [name]: settings }));
  };

  const handleUpdateInfo = (info: Partial<CompanyInfo>) => {
    setCompanyInfo(prev => ({ ...prev, ...info }));
  };

  return (
    <div className="min-h-screen flex flex-col md:flex-row">
      {/* Sidebar */}
      <nav className="w-full md:w-64 bg-slate-900 text-white p-6 space-y-8 no-print shrink-0">
        <div className="flex items-center space-x-3">
          <div className="p-2 bg-blue-600 rounded-lg">
            <Building2 className="w-6 h-6" />
          </div>
          <h1 className="text-xl font-bold tracking-tight">NILE FLEET</h1>
        </div>

        <div className="space-y-1">
          <button 
            onClick={() => setActiveTab('bookings')}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-colors ${activeTab === 'bookings' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:bg-slate-800'}`}
          >
            <FileSpreadsheet className="w-5 h-5" />
            <span className="font-medium">Bookings</span>
          </button>
          <button 
            onClick={() => setActiveTab('customers')}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-colors ${activeTab === 'customers' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:bg-slate-800'}`}
          >
            <Users className="w-5 h-5" />
            <span className="font-medium">Customers</span>
          </button>
          <button 
            onClick={() => setActiveTab('info')}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-colors ${activeTab === 'info' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:bg-slate-800'}`}
          >
            <Info className="w-5 h-5" />
            <span className="font-medium">My Info</span>
          </button>
        </div>

        <div className="pt-8 border-t border-slate-800">
          <p className="text-xs text-slate-500 uppercase tracking-wider font-semibold mb-4">Invoice Theme</p>
          <div className="grid grid-cols-1 gap-2">
            {THEMES.map(theme => (
              <button
                key={theme.id}
                onClick={() => setSelectedTheme(theme.id)}
                className={`text-sm px-3 py-1.5 rounded border transition-all text-left ${selectedTheme === theme.id ? 'border-blue-500 bg-blue-500/10 text-blue-400' : 'border-slate-700 text-slate-400 hover:border-slate-500'}`}
              >
                {theme.name}
              </button>
            ))}
          </div>
        </div>
      </nav>

      {/* Main Content */}
      <main className="flex-1 bg-slate-50 p-4 md:p-8 overflow-y-auto">
        <div className="max-w-6xl mx-auto">
          {activeTab === 'bookings' && (
            <BookingScreen 
              invoices={invoices} 
              onPreview={(inv) => setSelectedInvoice(inv)} 
            />
          )}
          {activeTab === 'customers' && (
            <CustomerScreen 
              settings={customerSettings} 
              onUpdate={handleUpdateCustomer} 
            />
          )}
          {activeTab === 'info' && (
            <InfoScreen 
              info={companyInfo} 
              onUpdate={handleUpdateInfo} 
            />
          )}
        </div>
      </main>

      {/* Invoice Modal */}
      {selectedInvoice && (
        <InvoiceModal 
          invoice={selectedInvoice} 
          theme={selectedTheme} 
          company={companyInfo}
          onClose={() => setSelectedInvoice(null)} 
        />
      )}
    </div>
  );
};

export default App;

import React from 'react';
import { Settings, Save } from 'lucide-react';
import { CustomerSettings } from '../types';

interface Props {
  settings: Record<string, CustomerSettings>;
  onUpdate: (name: string, settings: CustomerSettings) => void;
}

const CustomerScreen: React.FC<Props> = ({ settings, onUpdate }) => {
  return (
    <div className="space-y-6">
      <div>
        <h2 className="text-2xl font-bold text-slate-800">Customer Settings</h2>
        <p className="text-slate-500">Configure billing preferences for each client detected in your system</p>
      </div>

      <div className="grid grid-cols-1 gap-6">
        {Object.values(settings).map((customer) => (
          <div key={customer.name} className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
            <div className="flex items-center justify-between mb-6">
              <div className="flex items-center space-x-3">
                <div className="w-10 h-10 bg-blue-100 text-blue-600 rounded-full flex items-center justify-center font-bold">
                  {customer.name.charAt(0)}
                </div>
                <div>
                  <h3 className="font-bold text-lg text-slate-900">{customer.name}</h3>
                  <p className="text-xs text-slate-400 uppercase tracking-wider">Client Configuration</p>
                </div>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="space-y-1">
                <label className="text-sm font-medium text-slate-700">Serial Prefix</label>
                <input 
                  type="text" 
                  value={customer.serialPrefix}
                  onChange={(e) => onUpdate(customer.name, { ...customer, serialPrefix: e.target.value })}
                  className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                  placeholder="e.g. INV-2026-"
                />
              </div>
              <div className="space-y-1">
                <label className="text-sm font-medium text-slate-700">Starting Serial</label>
                <input 
                  type="number" 
                  value={customer.startingSerial}
                  onChange={(e) => onUpdate(customer.name, { ...customer, startingSerial: parseInt(e.target.value) || 1 })}
                  className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                />
              </div>
              <div className="space-y-1">
                <label className="text-sm font-medium text-slate-700">Payment Due (Days)</label>
                <input 
                  type="number" 
                  value={customer.dueDateDays}
                  onChange={(e) => onUpdate(customer.name, { ...customer, dueDateDays: parseInt(e.target.value) || 0 })}
                  className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                />
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default CustomerScreen;

import React from 'react';
import { Upload, Trash2, Building2 } from 'lucide-react';
import { CompanyInfo } from '../types';

interface Props {
  info: CompanyInfo;
  onUpdate: (info: Partial<CompanyInfo>) => void;
}

const InfoScreen: React.FC<Props> = ({ info, onUpdate }) => {
  const handleFileUpload = (field: 'logo' | 'signature' | 'watermark', e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        onUpdate({ [field]: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const removeFile = (field: 'logo' | 'signature' | 'watermark') => {
    onUpdate({ [field]: null });
  };

  return (
    <div className="space-y-8">
      <div>
        <h2 className="text-2xl font-bold text-slate-800">Company Information</h2>
        <p className="text-slate-500">Manage Nile Fleet company profile and branding assets</p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Profile Info */}
        <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm space-y-4">
          <h3 className="text-lg font-bold text-slate-800 mb-4 flex items-center gap-2">
            <Building2 className="w-5 h-5 text-blue-600" />
            General Profile
          </h3>
          <div className="grid grid-cols-1 gap-4">
            <div className="space-y-1">
              <label className="text-sm font-medium text-slate-700">Company Name</label>
              <input 
                type="text" 
                value={info.name}
                onChange={(e) => onUpdate({ name: e.target.value })}
                className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
              />
            </div>
            <div className="space-y-1">
              <label className="text-sm font-medium text-slate-700">Full Address</label>
              <textarea 
                rows={3}
                value={info.address}
                onChange={(e) => onUpdate({ address: e.target.value })}
                className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none resize-none"
              />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1">
                <label className="text-sm font-medium text-slate-700">Email Address</label>
                <input 
                  type="email" 
                  value={info.email}
                  onChange={(e) => onUpdate({ email: e.target.value })}
                  className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                />
              </div>
              <div className="space-y-1">
                <label className="text-sm font-medium text-slate-700">Phone Number</label>
                <input 
                  type="text" 
                  value={info.phone}
                  onChange={(e) => onUpdate({ phone: e.target.value })}
                  className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                />
              </div>
            </div>
          </div>
        </div>

        {/* Assets */}
        <div className="space-y-8">
          {/* Logo & Signature */}
          <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm space-y-6">
            <h3 className="text-lg font-bold text-slate-800">Branding Assets</h3>

            <AssetUpload 
              label="Company Logo"
              value={info.logo}
              onUpload={(e) => handleFileUpload('logo', e)}
              onClear={() => removeFile('logo')}
            />

            <AssetUpload 
              label="Digital Signature"
              value={info.signature}
              onUpload={(e) => handleFileUpload('signature', e)}
              onClear={() => removeFile('signature')}
            />

            <AssetUpload 
              label="Invoice Watermark"
              value={info.watermark}
              onUpload={(e) => handleFileUpload('watermark', e)}
              onClear={() => removeFile('watermark')}
            />
          </div>
        </div>
      </div>
    </div>
  );
};

const AssetUpload: React.FC<{
  label: string;
  value: string | null;
  onUpload: (e: React.ChangeEvent<HTMLInputElement>) => void;
  onClear: () => void;
}> = ({ label, value, onUpload, onClear }) => (
  <div className="space-y-2">
    <label className="text-sm font-semibold text-slate-700">{label}</label>
    <div className="flex items-center gap-4">
      {value ? (
        <div className="relative group">
          <img src={value} alt={label} className="h-20 w-auto rounded border bg-slate-50 object-contain p-2" />
          <button 
            onClick={onClear}
            className="absolute -top-2 -right-2 bg-red-500 text-white p-1 rounded-full opacity-0 group-hover:opacity-100 transition-opacity shadow-lg"
          >
            <Trash2 className="w-3 h-3" />
          </button>
        </div>
      ) : (
        <label className="h-20 flex-1 flex flex-col items-center justify-center border-2 border-dashed border-slate-200 rounded-lg cursor-pointer hover:bg-slate-50 hover:border-blue-400 transition-all">
          <Upload className="w-5 h-5 text-slate-400 mb-1" />
          <span className="text-xs text-slate-500">Upload Image</span>
          <input type="file" className="hidden" accept="image/*" onChange={onUpload} />
        </label>
      )}
    </div>
  </div>
);

export default InfoScreen;

import React from 'react';
import { Invoice, InvoiceTheme, CompanyInfo } from '../types';

interface Props {
  invoice: Invoice;
  theme: InvoiceTheme;
  company: CompanyInfo;
}

const InvoiceRenderer: React.FC<Props> = ({ invoice, theme, company }) => {
  const renderHeader = () => {
    switch (theme) {
      case 'dark':
        return (
          <div className="bg-slate-900 text-white p-10 -m-10 mb-10 flex justify-between items-start">
            <div className="space-y-4">
              {company.logo && <img src={company.logo} className="h-12 w-auto brightness-0 invert" />}
              <h1 className="text-4xl font-black uppercase tracking-tighter">{company.name}</h1>
              <p className="text-slate-400 max-w-xs text-sm">{company.address}</p>
            </div>
            <div className="text-right">
              <h2 className="text-5xl font-light opacity-50 mb-4">INVOICE</h2>
              <p className="text-blue-400 font-bold">{invoice.serialNumber}</p>
            </div>
          </div>
        );
      case 'bold':
        return (
          <div className="border-b-8 border-slate-900 pb-10 mb-10 flex justify-between items-end">
            <div className="space-y-6">
              <div className="inline-block bg-slate-900 text-white px-4 py-2 text-2xl font-bold">
                {company.name}
              </div>
              <p className="text-slate-600 font-bold text-lg uppercase">{company.address}</p>
            </div>
            <div className="text-right">
              <span className="block text-sm font-black text-slate-400 mb-1">REFERENCE #</span>
              <span className="text-3xl font-black">{invoice.serialNumber}</span>
            </div>
          </div>
        );
      case 'elegant':
        return (
          <div className="text-center mb-16 space-y-6">
            <h1 className="font-['Playfair_Display'] text-5xl italic font-bold text-slate-800">{company.name}</h1>
            <div className="flex items-center justify-center gap-4 text-sm uppercase tracking-[0.2em] text-slate-500 border-y border-slate-200 py-4">
              <span>{company.phone}</span>
              <span className="w-1.5 h-1.5 bg-slate-300 rounded-full"></span>
              <span>{company.email}</span>
            </div>
          </div>
        );
      case 'industrial':
        return (
          <div className="grid grid-cols-2 border-4 border-slate-900 p-8 mb-10">
            <div>
              <h1 className="text-4xl font-black italic tracking-tighter uppercase mb-2">TRANSPORT LOG</h1>
              <p className="font-mono text-sm">{company.name} // {company.address}</p>
            </div>
            <div className="text-right flex flex-col justify-between">
              <h2 className="text-xl font-bold bg-slate-900 text-white inline-block px-2 self-end">BILLING DOC</h2>
              <p className="font-mono">{invoice.serialNumber}</p>
            </div>
          </div>
        );
      default:
        return (
          <div className="flex justify-between items-start mb-12">
            <div className="space-y-4">
              {company.logo ? (
                <img src={company.logo} className="h-16 w-auto" alt="Logo" />
              ) : (
                <div className="w-16 h-16 bg-blue-600 rounded-xl flex items-center justify-center text-white text-2xl font-bold">
                  {company.name.charAt(0)}
                </div>
              )}
              <div>
                <h1 className="text-2xl font-bold text-slate-900">{company.name}</h1>
                <p className="text-sm text-slate-500 max-w-xs">{company.address}</p>
              </div>
            </div>
            <div className="text-right space-y-2">
              <h2 className="text-4xl font-bold text-slate-300 uppercase tracking-wider">Invoice</h2>
              <p className="text-lg font-bold text-slate-900">{invoice.serialNumber}</p>
              <div className="text-sm text-slate-500">
                <p>Date: {invoice.date}</p>
                <p className="text-blue-600 font-semibold">Due: {invoice.dueDate}</p>
              </div>
            </div>
          </div>
        );
    }
  };

  const tableClasses = () => {
    switch (theme) {
      case 'grid': return "w-full border-collapse font-mono text-sm";
      case 'soft': return "w-full rounded-2xl overflow-hidden shadow-sm";
      default: return "w-full";
    }
  };

  const renderTable = () => {
    return (
      <div className="mb-10 overflow-hidden">
        <table className={tableClasses()}>
          <thead className={`
            ${theme === 'dark' ? 'bg-slate-800 text-slate-300' : ''}
            ${theme === 'minimal' ? 'border-b-2 border-slate-100' : ''}
            ${theme === 'grid' ? 'bg-blue-50 text-blue-900' : ''}
            ${theme === 'industrial' ? 'bg-slate-200 uppercase font-black' : ''}
            ${theme === 'soft' ? 'bg-indigo-50 text-indigo-900' : ''}
            ${!['dark', 'minimal', 'grid', 'industrial', 'soft'].includes(theme) ? 'bg-slate-50' : ''}
          `}>
            <tr>
              <th className="px-4 py-3 text-left text-xs font-bold uppercase">Unit #</th>
              <th className="px-4 py-3 text-left text-xs font-bold uppercase">Route (Go/Gi)</th>
              <th className="px-4 py-3 text-left text-xs font-bold uppercase">Trucker</th>
              <th className="px-4 py-3 text-right text-xs font-bold uppercase">Rate</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {invoice.items.map((item, i) => (
              <tr key={i} className={theme === 'grid' ? 'border border-blue-100' : ''}>
                <td className="px-4 py-4">
                  <span className="font-bold text-slate-900 block">{item.UnitNumber}</span>
                  <span className="text-xs text-slate-400">Shipper: {item.Shipper}</span>
                </td>
                <td className="px-4 py-4 text-sm text-slate-600">
                  {item.PortGo} → {item.PortGi}
                </td>
                <td className="px-4 py-4 text-sm text-slate-500">{item.Trucker || 'N/A'}</td>
                <td className="px-4 py-4 text-right font-bold text-slate-900">
                  ${item.Rate.toLocaleString()}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    );
  };

  const renderFooter = () => {
    return (
      <div className="flex justify-between items-end mt-12 pt-8 border-t border-slate-100">
        <div className="space-y-4">
          <div className="space-y-1">
            <h4 className="text-xs font-black uppercase text-slate-400">Bill To</h4>
            <p className="text-lg font-bold text-slate-900">{invoice.customer}</p>
          </div>
          {company.signature && (
            <div className="pt-4">
              <p className="text-xs text-slate-400 mb-2">Authorized Signature</p>
              <img src={company.signature} className="h-16 w-auto" alt="Signature" />
            </div>
          )}
        </div>
        <div className="w-64 space-y-3">
          <div className="flex justify-between text-sm text-slate-500">
            <span>Subtotal</span>
            <span>${invoice.total.toLocaleString()}</span>
          </div>
          <div className="flex justify-between text-sm text-slate-500">
            <span>Tax (0%)</span>
            <span>$0.00</span>
          </div>
          <div className={`flex justify-between items-center p-3 rounded-lg ${theme === 'dark' ? 'bg-blue-600 text-white' : 'bg-slate-900 text-white'}`}>
            <span className="text-xs font-bold uppercase">Total Amount</span>
            <span className="text-xl font-black">${invoice.total.toLocaleString()}</span>
          </div>
        </div>
      </div>
