        </div>

        <div className="pt-8 border-t border-slate-800">
          <p className="text-xs text-slate-500 uppercase tracking-wider font-semibold mb-4">Invoice Theme</p>
          <div className="grid grid-cols-1 gap-2">
            {THEMES.map(theme => (
              <button
                key={theme.id}
                onClick={() => setSelectedTheme(theme.id)}
                className={`text-sm px-3 py-1.5 rounded border transition-all text-left ${selectedTheme === theme.id ? 'border-blue-500 bg-blue-500/10 text-blue-400' : 'border-slate-700 text-slate-400 hover:border-slate-500'}`}
              >
                {theme.name}
              </button>
            ))}
          </div>
        </div>
      </nav>

      {/* Main Content */}
      <main className="flex-1 bg-slate-50 p-4 md:p-8 overflow-y-auto">
        <div className="max-w-6xl mx-auto">
          {activeTab === 'bookings' && (
            <BookingScreen 
              invoices={invoices} 
              onPreview={(inv) => setSelectedInvoice(inv)} 
            />
          )}
          {activeTab === 'customers' && (
            <CustomerScreen 
              settings={customerSettings} 
              onUpdate={handleUpdateCustomer} 
            />
          )}
          {activeTab === 'info' && (
            <InfoScreen 
              info={companyInfo} 
              onUpdate={handleUpdateInfo} 
            />
          )}
        </div>
      </main>

      {/* Invoice Modal */}
      {selectedInvoice && (
        <InvoiceModal 
          invoice={selectedInvoice} 
          theme={selectedTheme} 
          company={companyInfo}
          onClose={() => setSelectedInvoice(null)} 
        />
      )}
    </div>
  );
};

export default App;

import React from 'react';
import { Upload, Trash2, Building2, ShieldCheck } from 'lucide-react';
import { CompanyInfo } from '../types';

interface Props {
  info: CompanyInfo;
  onUpdate: (info: Partial<CompanyInfo>) => void;
}

const InfoScreen: React.FC<Props> = ({ info, onUpdate }) => {
  const handleFileUpload = (field: 'logo' | 'signature' | 'watermark', e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        onUpdate({ [field]: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const removeFile = (field: 'logo' | 'signature' | 'watermark') => {
    onUpdate({ [field]: null });
  };

  return (
    <div className="space-y-8">
      <div>
        <h2 className="text-2xl font-bold text-slate-800">Company Information</h2>
        <p className="text-slate-500">Manage Nile Fleet company profile and branding assets</p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Profile Info */}
        <div className="space-y-8">
          <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm space-y-4">
            <h3 className="text-lg font-bold text-slate-800 mb-4 flex items-center gap-2">
              <Building2 className="w-5 h-5 text-blue-600" />
              General Profile
            </h3>
            <div className="grid grid-cols-1 gap-4">
              <div className="space-y-1">
                <label className="text-sm font-medium text-slate-700">Company Name</label>
                <input 
                  type="text" 
                  value={info.name}
                  onChange={(e) => onUpdate({ name: e.target.value })}
                  className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                />
              </div>
              <div className="space-y-1">
                <label className="text-sm font-medium text-slate-700">Full Address</label>
                <textarea 
                  rows={2}
                  value={info.address}
                  onChange={(e) => onUpdate({ address: e.target.value })}
                  className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none resize-none"
                />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-sm font-medium text-slate-700">Company Email</label>
                  <input 
                    type="email" 
                    value={info.email}
                    onChange={(e) => onUpdate({ email: e.target.value })}
                    className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                  />
                </div>
                <div className="space-y-1">
                  <label className="text-sm font-medium text-slate-700">Company Phone</label>
                  <input 
                    type="text" 
                    value={info.phone}
                    onChange={(e) => onUpdate({ phone: e.target.value })}
                    className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                  />
                </div>
              </div>
            </div>
          </div>

          <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm space-y-4">
            <h3 className="text-lg font-bold text-slate-800 mb-4 flex items-center gap-2">
              <ShieldCheck className="w-5 h-5 text-green-600" />
              Authorized Person Details
            </h3>
            <div className="grid grid-cols-1 gap-4">
              <div className="space-y-1">
                <label className="text-sm font-medium text-slate-700">Authorized Name</label>
                <input 
                  type="text" 
                  value={info.authName}
                  onChange={(e) => onUpdate({ authName: e.target.value })}
