                  />
                </div>
                <div className="space-y-1">
                  <label className="text-sm font-medium text-slate-700">Authorized Email</label>
                  <input 
                    type="email" 
                    value={info.authEmail}
                    onChange={(e) => onUpdate({ authEmail: e.target.value })}
