            ${theme === 'soft' ? 'bg-indigo-50 text-indigo-900' : ''}
            ${!['dark', 'minimal', 'grid', 'industrial', 'soft'].includes(theme) ? 'bg-slate-50' : ''}
          `}>
            <tr>
              <th className="px-3 py-2 text-left text-[10px] font-bold uppercase">Unit #</th>
              <th className="px-3 py-2 text-left text-[10px] font-bold uppercase">Route</th>
              <th className="px-3 py-2 text-left text-[10px] font-bold uppercase">Trucker</th>
              <th className="px-3 py-2 text-right text-[10px] font-bold uppercase">Rate</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {invoice.items.map((item, i) => (
              <tr key={i} className={theme === 'grid' ? 'border border-blue-100' : ''}>
                <td className="px-3 py-3">
                  <span className="font-bold text-slate-900 block">{item.UnitNumber}</span>
                  <span className="text-[10px] text-slate-400">Shipper: {item.Shipper}</span>
                </td>
                <td className="px-3 py-3 text-xs text-slate-600">
                  {item.PortGo} → {item.PortGi}
                </td>
                <td className="px-3 py-3 text-xs text-slate-500">{item.Trucker || '—'}</td>
                <td className="px-3 py-3 text-right font-bold text-slate-900">
                  ${item.Rate.toLocaleString()}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    );
  };

  const renderFooter = () => {
    return (
      <div className="flex justify-between items-end mt-auto pt-6 border-t border-slate-100">
        <div className="space-y-4">
          <div className="space-y-1">
            <h4 className="text-[10px] font-black uppercase text-slate-400">Bill To</h4>
            <p className="text-base font-bold text-slate-900">{invoice.customer}</p>
          </div>
          <div className="pt-2">
            <p className="text-[10px] font-bold uppercase text-slate-400 mb-2">Authorized By</p>
            {company.signature && (
              <img src={company.signature} className="h-24 w-auto mb-2" alt="Signature" />
