            <div className="text-[11px] space-y-0.5 border-l-2 border-slate-200 pl-3">
              <p className="font-bold text-slate-900 uppercase">{company.authName}</p>
              <p className="text-slate-500">{company.authPhone}</p>
              <p className="text-slate-500">{company.authEmail}</p>
            </div>
          </div>
        </div>
        <div className="w-56 space-y-2">
          <div className="flex justify-between text-xs text-slate-500">
            <span>Subtotal</span>
            <span>${invoice.total.toLocaleString()}</span>
          </div>
          <div className="flex justify-between text-xs text-slate-500">
            <span>Tax (0%)</span>
            <span>$0.00</span>
          </div>
          <div className={`flex justify-between items-center p-3 rounded-lg ${theme === 'dark' ? 'bg-blue-600 text-white' : 'bg-slate-900 text-white'}`}>
            <span className="text-[10px] font-bold uppercase">Total Amount</span>
            <span className="text-lg font-black">${invoice.total.toLocaleString()}</span>
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className={`invoice-container relative shadow-2xl overflow-hidden ${theme === 'dark' ? 'bg-slate-950' : 'bg-white'}`}>
      {/* Watermark */}
      {company.watermark && (
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 opacity-[0.03] pointer-events-none rotate-12">
          <img src={company.watermark} className="w-[140mm] h-auto grayscale" />
        </div>
      )}

      {renderHeader()}

      {theme === 'compact' && (
        <div className="bg-slate-50 p-3 mb-6 rounded grid grid-cols-4 gap-4 text-[10px]">
          <div><p className="text-slate-400 uppercase">Booking</p><p className="font-bold">{invoice.bookingNo}</p></div>
          <div><p className="text-slate-400 uppercase">Date</p><p className="font-bold">{invoice.date}</p></div>
          <div><p className="text-slate-400 uppercase">Due Date</p><p className="font-bold">{invoice.dueDate}</p></div>
          <div><p className="text-slate-400 uppercase">Currency</p><p className="font-bold">USD</p></div>
        </div>
      )}

      {renderTable()}

      {renderFooter()}

      <div className="mt-8 text-center text-[9px] text-slate-400 uppercase tracking-[0.2em] border-t border-slate-50 pt-4">
        Thank you for choosing {company.name} for your logistics needs.
      </div>
    </div>
  );
};

