            ${!['dark', 'minimal', 'grid', 'industrial', 'soft'].includes(theme) ? 'bg-slate-50' : ''}
          `}>
            <tr>
              <th className="px-3 py-2 text-left text-[10px] font-bold uppercase">Unit #</th>
              <th className="px-3 py-2 text-left text-[10px] font-bold uppercase">Route</th>
              <th className="px-3 py-2 text-left text-[10px] font-bold uppercase">Trucker</th>
              <th className="px-3 py-2 text-left text-[10px] font-bold uppercase">Shipper</th>
              <th className="px-3 py-2 text-right text-[10px] font-bold uppercase">Rate</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {invoice.items.map((item, i) => (
              <tr key={i} className={theme === 'grid' ? 'border border-blue-100' : ''}>
