              <p className="text-[8px] text-slate-400 mt-2 uppercase tracking-tighter">Verified: {generationTimestamp}</p>
            </div>
          </div>
        </div>

        <div className={`mt-12 pt-6 border-t text-center text-[9px] uppercase tracking-[0.3em] ${isDark ? 'border-slate-900 text-slate-700' : 'border-slate-50 text-slate-400'}`}>
          Logistics Powered by {company.name} • {company.email}
        </div>
      </div>
    );
  };

  return (
    <div className={`invoice-container relative shadow-2xl overflow-hidden transition-all duration-500 ${getThemeBaseStyles()}`}>
      {/* Watermark */}
      {company.watermark && (
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 opacity-[0.03] pointer-events-none rotate-12 scale-150">
          <img src={company.watermark} className="w-[140mm] h-auto grayscale" />
        </div>
      )}

      {renderHeader()}
      {renderBillTo()}
      {renderTable()}
      {renderFooter()}

      {/* Stamp / Decorative Element for Industrial */}
      {theme === 'industrial' && (
        <div className="absolute top-12 right-12 border-4 border-black p-2 rotate-12 opacity-20 font-black text-xl pointer-events-none uppercase">
          ORIGINAL COPY
        </div>
      )}
    </div>
  );
};

