                <p className={`font-black uppercase tracking-tight ${isDark ? 'text-slate-200' : 'text-slate-900'}`}>{company.authName}</p>
                <p className="text-[10px] opacity-60 font-bold">{company.authJobTitle}</p>
                <div className={`text-[10px] mt-2 ${isDark ? 'text-slate-500' : 'text-slate-400'}`}>
