              </div>
            </div>
          </div>

          <div className="w-72">
            <div className="space-y-2 mb-6">
              <div className="flex justify-between text-xs">
                <span className={isDark ? 'text-slate-600' : 'text-slate-400'}>Net Amount</span>
                <span className={isDark ? 'text-slate-300' : 'text-slate-900'}>{invoice.total.toLocaleString()} EGP</span>
              </div>
            </div>

            <div className={`p-4 rounded-xl ${isDark ? 'bg-blue-600 text-white' : 'bg-slate-950 text-white'} mb-6`}>
              <div className="flex justify-between items-center">
                <span className="text-[10px] font-black uppercase tracking-widest opacity-75">Total EGP</span>
                <span className="text-2xl font-black">{invoice.total.toLocaleString()}</span>
              </div>
            </div>
          </div>
        </div>

        {/* Official Notes Section */}
        <div className={`mt-8 p-4 rounded-lg border ${isDark ? 'bg-slate-900/40 border-slate-800' : 'bg-slate-50 border-slate-100'}`}>
          <h4 className={`text-[10px] font-black uppercase mb-2 ${isDark ? 'text-blue-400' : 'text-blue-600'}`}>Official Notes</h4>
          <p className={`text-[10px] leading-relaxed ${isDark ? 'text-slate-400' : 'text-slate-600'}`}>
            <span className="font-bold">Settlement Note:</span> Thank you for your business! We kindly request full settlement by <span className="underline">{invoice.dueDate}</span>. For smooth processing, please include the invoice number in your payment reference. We value your feedback, so please review these details within one week of receipt; after this time, the invoice will be considered final and approved. We appreciate your cooperation.
          </p>
        </div>

        <div className={`mt-10 pt-6 border-t flex flex-col justify-center items-center text-[10px] uppercase tracking-[0.3em] font-normal ${isDark ? 'border-slate-900 text-slate-700' : 'border-slate-50 text-slate-400'}`}>
          <div>NILE FLEET GENSET</div>
          <div className="mt-1 opacity-60">POWERED BY BEBITO</div>
        </div>
      </div>
    );
  };

  return (
    <div className={`invoice-container relative shadow-2xl overflow-hidden transition-all duration-500 ${getThemeBaseStyles()}`}>
      {/* Watermark */}
      {company.watermark && (
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 opacity-[0.03] pointer-events-none rotate-12 scale-150">
          <img src={company.watermark} className="w-[140mm] h-auto grayscale" />
        </div>
      )}

      {renderHeader()}
      {renderBillTo()}
      {renderTable()}
      {renderFooter()}

      {/* Stamp / Decorative Element for Industrial */}
      {theme === 'industrial' && (
        <div className="absolute top-12 right-12 border-4 border-black p-2 rotate-12 opacity-20 font-black text-xl pointer-events-none uppercase">
          ORIGINAL COPY
        </div>
      )}
    </div>
  );
};

