              <h4 className="text-[10px] uppercase tracking-widest text-amber-700 mb-4 not-italic font-bold">Operation Ref</h4>
              <p className="text-4xl font-black tracking-widest text-amber-900 border-b-2 border-amber-900 inline-block px-4 py-1">{invoice.bookingNo}</p>
            </div>
          </div>
        );
      case 'industrial':
        return (
          <div className="grid grid-cols-3 gap-0 mb-12 border-2 border-black divide-x-2 divide-black">
             <div className="p-4 bg-black text-white">
                <h4 className="text-[10px] font-black mb-2">RECIPIENT_NAME</h4>
                <p className="text-xl font-black truncate">{invoice.customer}</p>
             </div>
             <div className="p-4 col-span-2 flex flex-col justify-center">
                <h4 className="text-[10px] font-black mb-1">TRANSACTION_ID / BOOKING</h4>
                <p className="text-4xl font-black tracking-tighter bg-yellow-200 px-2 inline-block self-start">{invoice.bookingNo}</p>
             </div>
          </div>
        );
      case 'grid':
        return (
          <div className="grid grid-cols-4 gap-0 mb-12 border-2 border-slate-900 divide-x-2 divide-slate-900">
            <div className="p-4 bg-slate-100 flex items-center">
               <div className="text-[10px] font-bold text-slate-500 uppercase">Bill To:</div>
            </div>
            <div className="col-span-3 p-4 flex justify-between items-center">
               <div>
                  <div className="text-2xl font-black uppercase">{invoice.customer}</div>
               </div>
               <div className="text-right border-l-2 border-slate-900 pl-6">
                  <div className="text-[8px] font-bold text-slate-400 uppercase">Master Booking</div>
                  <div className="text-2xl font-black text-slate-900">{invoice.bookingNo}</div>
               </div>
            </div>
          </div>
        );
      default:
        return (
          <div className="mb-12 border-l-4 border-slate-200 pl-6 flex justify-between items-start">
            <div>
              <h4 className="text-[10px] font-black uppercase text-slate-400 mb-2">Billing Information</h4>
              <p className="text-3xl font-black text-slate-900 tracking-tight">{invoice.customer}</p>
            </div>
            <div className="text-right border-r-8 border-slate-900 pr-4">
              <div className="text-[10px] font-black uppercase text-blue-600 mb-1">Booking Number</div>
              <div className="text-4xl font-black tracking-tighter text-slate-900">{invoice.bookingNo}</div>
            </div>
          </div>
        );
    }
  };

  const renderTable = () => {
    let containerClass = "mb-12 overflow-hidden";
    let tableClass = "w-full text-sm border-collapse";
    let theadClass = "bg-slate-100 text-[10px] font-black uppercase tracking-widest text-slate-500 border-y-2 border-slate-900";
    let thClass = "px-4 py-4 text-left";
    let tdClass = "px-4 py-5 border-b border-slate-100";
    let rateClass = "text-right font-black text-slate-900";

    if (theme === 'bold') {
      theadClass = "bg-blue-600 text-white text-[11px] font-black uppercase tracking-widest";
      tdClass = "px-4 py-6 border-b-4 border-slate-900";
      rateClass = "text-right text-xl font-black bg-yellow-400 text-slate-900 px-2";
    } else if (theme === 'elegant') {
      theadClass = "bg-white text-amber-700 font-bold uppercase text-[9px] tracking-[0.3em] border-y-2 border-amber-100";
      tdClass = "px-4 py-6 italic border-b border-amber-50";
      rateClass = "text-right text-slate-800 font-normal tracking-widest";
    } else if (theme === 'industrial') {
      theadClass = "bg-black text-white text-[10px] font-black border-2 border-black";
      tdClass = "px-4 py-3 border-2 border-black font-black";
      thClass = "px-4 py-2 text-left";
    } else if (theme === 'grid') {
      theadClass = "bg-slate-900 text-white text-[10px] font-bold";
      tdClass = "px-4 py-4 border-2 border-slate-900 font-bold";
      containerClass = "mb-12 border-collapse";
    } else if (theme === 'soft') {
      theadClass = "bg-teal-500 text-white text-[10px] font-bold uppercase rounded-t-xl";
      tdClass = "px-4 py-4 bg-white border-b border-teal-50 text-slate-600";
      containerClass = "mb-12 rounded-2xl overflow-hidden border-2 border-teal-50";
    }

    return (
      <div className={containerClass}>
        <table className={tableClass}>
          <thead className={theadClass}>
            <tr>
              <th className={thClass}>Unit Number</th>
              <th className={thClass}>Route / Transit</th>
              <th className={thClass}>Trucker</th>
              <th className={thClass}>Shipper</th>
              <th className={`${thClass} text-right`}>Service Rate</th>
            </tr>
          </thead>
          <tbody>
            {invoice.items.map((item, i) => (
              <tr key={i} className={theme === 'soft' && i % 2 === 0 ? 'bg-teal-50/20' : ''}>
                <td className={tdClass}>
                  <div className="font-black text-slate-900">{item.UnitNumber}</div>
                </td>
                <td className={tdClass}>
                  <div className="flex items-center gap-2 font-bold text-[11px]">
                    <span className="opacity-40">{item.PortGo}</span>
                    <span className="text-blue-500">→</span>
                    <span className="opacity-40">{item.PortGi}</span>
                  </div>
                </td>
                <td className={tdClass}>
                  <div className="opacity-70">{item.Trucker || '---'}</div>
                </td>
                <td className={tdClass}>
                  <div className="opacity-70">{item.Shipper || '---'}</div>
                </td>
                <td className={`${tdClass} ${rateClass}`}>
                  {item.Rate.toLocaleString()} <span className="text-[10px] opacity-40">EGP</span>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    );
  };

  const renderFooter = () => {
    let totalBoxClass = "p-8 bg-slate-900 text-white rounded-2xl w-80";
    let footerTaglineClass = "mt-20 pt-10 border-t flex flex-col items-center text-[10px] uppercase tracking-[0.4em]";

    if (theme === 'bold') {
      totalBoxClass = "p-10 bg-blue-600 text-white border-8 border-slate-900 w-96";
    } else if (theme === 'elegant') {
      totalBoxClass = "p-8 border-2 border-amber-200 text-amber-900 w-80 text-center italic";
    } else if (theme === 'industrial') {
      totalBoxClass = "p-4 border-4 border-black bg-white text-black w-80 flex flex-col items-end";
    } else if (theme === 'soft') {
      totalBoxClass = "p-8 bg-teal-600 text-white rounded-[2rem] w-80 shadow-xl shadow-teal-100";
    }

    return (
      <div className="mt-auto flex flex-col">
        {/* 1. Settlement Note */}
        <div className="mb-12 p-8 bg-slate-50 border-2 border-slate-100 rounded-2xl">
          <h5 className="text-[11px] font-black uppercase text-blue-600 mb-4 tracking-widest border-b border-blue-100 pb-2 inline-block">Settlement Note</h5>
          <p className="text-[11px] text-slate-600 leading-relaxed font-semibold italic">
            Thank you for your business! We kindly request full settlement by <span className="text-slate-900 font-black underline decoration-blue-500 decoration-2 underline-offset-4">{invoice.dueDate}</span>. 
            For smooth processing, please include the invoice number in your payment reference. We value your feedback, so please review these details within one week of receipt; after this time, the invoice will be considered final and approved. We appreciate your cooperation.
          </p>
        </div>

        {/* 2. Rate and Authorization (The Last Content Block) */}
        <div className="flex flex-col md:flex-row justify-between items-end gap-12 pt-8 border-t border-slate-100">
          <div className="max-w-xl pb-4">
             <h4 className="text-[10px] font-black uppercase text-slate-400 mb-4 tracking-widest">Authorized Endorsement</h4>
             <div className="flex items-center gap-6">
               {company.signature && (
                 <img src={company.signature} className="h-32 w-auto grayscale mix-blend-multiply object-contain border-r border-slate-100 pr-6" alt="Signature" />
               )}
               <div className="space-y-1 border-l-4 border-blue-600 pl-4">
                 <p className="text-2xl font-black text-slate-900 uppercase tracking-tight leading-none">{company.authName}</p>
                 <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{company.authJobTitle}</p>
                 <div className="pt-2 text-[10px] font-medium text-slate-400 space-y-0.5">
                    <p>{company.authPhone}</p>
                    <p>{company.authEmail}</p>
                 </div>
               </div>
             </div>
          </div>

          <div className={`${totalBoxClass} shrink-0`}>
             <div className="flex justify-between items-center mb-2 uppercase tracking-[0.2em] font-bold text-[10px] opacity-60">
                <span>Subtotal Net</span>
                <span>{invoice.total.toLocaleString()}</span>
             </div>
             <div className="h-px bg-white/20 my-4"></div>
             <div className="flex flex-col items-end">
                <span className="text-[11px] font-black uppercase tracking-[0.4em] mb-1">Grand Total EGP</span>
                <span className="text-6xl font-black tabular-nums tracking-tighter">{invoice.total.toLocaleString()}</span>
             </div>
          </div>
        </div>

        {/* Branding Footer Tagline */}
        <div className={footerTaglineClass}>
          <div className="font-black text-slate-900 mb-1">NILE FLEET GENSET</div>
          <div className="opacity-40 font-bold text-[8px]">POWERED BY BEBITO</div>
        </div>
      </div>
    );
  };

  return (
    <div className={`invoice-container relative shadow-2xl overflow-hidden transition-all duration-500 ${getThemeBaseStyles()}`}>
      {/* Watermark */}
      {company.watermark && (
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 opacity-[0.04] pointer-events-none rotate-45 scale-150">
          <img src={company.watermark} className="w-[120mm] h-auto grayscale" />
        </div>
      )}

      {renderHeader()}
      {renderBillTo()}
      {renderTable()}
      {renderFooter()}

      {/* Decorative Stamp for Classic/Industrial */}
      {(theme === 'industrial' || theme === 'classic' || theme === 'bold') && (
        <div className="absolute top-24 right-48 border-4 border-red-500/20 rounded-full w-24 h-24 flex items-center justify-center -rotate-12 pointer-events-none">
           <div className="text-[8px] font-black text-red-500/20 text-center uppercase tracking-widest">
             ORIGINAL<br/>DOCUMENT<br/>NILE FLEET
           </div>
        </div>
      )}
    </div>
  );
};

export default InvoiceRenderer;

export interface BookingRow {
  Customer: string;
  BookingNo: string;
  UnitNumber: string;
  PortGo: string;
  PortGi: string;
  Trucker: string;
  Shipper: string;
  Rate: number;
  Date: string;
}

export interface CustomerSettings {
  name: string;
  dueDateDays: number;
  serialPrefix: string;
  startingSerial: number;
}

export interface CompanyInfo {
  name: string;
  address: string;
  email: string;
  phone: string;
  authName: string;
  authJobTitle: string;
  authPhone: string;
  authEmail: string;
  logo: string | null;
  signature: string | null;
  watermark: string | null;
}

export type InvoiceTheme = 
  | 'minimal' 
  | 'corporate' 
  | 'elegant' 
  | 'bold' 
  | 'dark' 
  | 'grid' 
  | 'classic' 
  | 'soft' 
  | 'industrial' 
  | 'compact';

export interface Invoice {
  id: string;
  bookingNo: string;
  customer: string;
  date: string;
  dueDate: string;
  serialNumber: string;
  items: BookingRow[];
  total: number;
  isStatement?: boolean;
  period?: string;
}

import React, { useRef, useState } from 'react';
import { Eye, Search, Upload, RefreshCcw, FileText, Calendar, ArrowRight, ChevronDown, ChevronUp } from 'lucide-react';
import { Invoice, BookingRow } from '../types';

interface Props {
  invoices: Invoice[];
  onPreview: (invoice: Invoice) => void;
  onImport: (data: BookingRow[]) => void;
  onLoadSample: () => void;
}

const BookingScreen: React.FC<Props> = ({ invoices, onPreview, onImport, onLoadSample }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [usedInvoiceIds, setUsedInvoiceIds] = useState<Set<string>>(new Set());
  const [showStatementTool, setShowStatementTool] = useState(false);
  const [statementForm, setStatementForm] = useState({
    customer: '',
    dateFrom: '',
    dateTo: ''
  });

  const fileInputRef = useRef<HTMLInputElement>(null);

  const filtered = invoices.filter(inv => 
    inv.bookingNo.toLowerCase().includes(searchTerm.toLowerCase()) ||
    inv.customer.toLowerCase().includes(searchTerm.toLowerCase()) ||
    inv.serialNumber.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const uniqueCustomers = Array.from(new Set(invoices.map(inv => inv.customer)));

  const handlePreview = (inv: Invoice) => {
    setUsedInvoiceIds(prev => new Set(prev).add(inv.id));
    onPreview(inv);
  };

  const generateStatement = () => {
    if (!statementForm.customer) return;

    // Collect all raw bookings for this customer (across all grouped invoices)
    const allMatchingBookings: BookingRow[] = [];
    invoices
      .filter(inv => inv.customer === statementForm.customer)
      .forEach(inv => {
        inv.items.forEach(item => {
          const itemDate = new Date(item.Date);
          const from = statementForm.dateFrom ? new Date(statementForm.dateFrom) : null;
          const to = statementForm.dateTo ? new Date(statementForm.dateTo) : null;

          if ((!from || itemDate >= from) && (!to || itemDate <= to)) {
            allMatchingBookings.push(item);
          }
        });
      });

    if (allMatchingBookings.length === 0) {
      alert("No operations found for the selected criteria.");
      return;
    }

    const statementPeriod = `${statementForm.dateFrom || 'Start'} to ${statementForm.dateTo || 'End'}`;

    const statementInvoice: Invoice = {
      id: `statement-${statementForm.customer}-${Date.now()}`,
      bookingNo: "MULTIPLE",
      customer: statementForm.customer,
      date: new Date().toISOString().split('T')[0],
      dueDate: "On Receipt",
      serialNumber: `SOA-${Date.now().toString().slice(-6)}`,
      items: allMatchingBookings,
      total: allMatchingBookings.reduce((sum, item) => sum + item.Rate, 0),
      isStatement: true,
      period: statementPeriod
    };

    onPreview(statementInvoice);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        const text = event.target?.result as string;
        const lines = text.split('\n');
        const parsed: BookingRow[] = lines.slice(1).filter(l => l.trim()).map(line => {
          const values = line.split(',');
          return {
            Customer: values[0]?.trim() || '',
            BookingNo: values[1]?.trim() || '',
            UnitNumber: values[2]?.trim() || '',
            PortGo: values[3]?.trim() || '',
            PortGi: values[4]?.trim() || '',
            Trucker: values[5]?.trim() || '',
            Shipper: values[6]?.trim() || '',
            Rate: parseFloat(values[7]) || 0,
            Date: values[8]?.trim() || new Date().toISOString().split('T')[0]
          };
        });
        onImport(parsed);
      };
      reader.readAsText(file);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-start justify-between gap-6">
        <div className="space-y-4">
          <div>
            <h2 className="text-2xl font-bold text-slate-800">Booking Operations</h2>
            <p className="text-slate-500">View and generate invoices from your logistics operations</p>
          </div>

          <div className="flex flex-wrap gap-2">
            <button 
              onClick={() => fileInputRef.current?.click()}
              className="inline-flex items-center space-x-2 px-4 py-2 bg-blue-600 hover:bg-blue-700 text-white text-sm font-semibold rounded-lg transition-colors shadow-sm shadow-blue-500/20"
            >
              <Upload className="w-4 h-4" />
              <span>Import CSV</span>
            </button>
            <input 
              type="file" 
              ref={fileInputRef} 
              className="hidden" 
              accept=".csv" 
              onChange={handleFileChange} 
            />

            <button 
              onClick={() => setShowStatementTool(!showStatementTool)}
              className={`inline-flex items-center space-x-2 px-4 py-2 text-sm font-semibold rounded-lg transition-all border ${showStatementTool ? 'bg-blue-50 border-blue-200 text-blue-700' : 'bg-white border-slate-200 text-slate-700 hover:bg-slate-50'}`}
            >
              <FileText className="w-4 h-4" />
              <span>Statement of Account</span>
              {showStatementTool ? <ChevronUp className="w-4 h-4 ml-1" /> : <ChevronDown className="w-4 h-4 ml-1" />}
            </button>

            <button 
              onClick={onLoadSample}
              className="inline-flex items-center space-x-2 px-4 py-2 bg-slate-100 hover:bg-slate-200 text-slate-700 text-sm font-semibold rounded-lg transition-colors border border-slate-200"
            >
              <RefreshCcw className="w-4 h-4" />
              <span>Reset Sample</span>
            </button>
          </div>
        </div>

        <div className="relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400" />
          <input 
            type="text" 
            placeholder="Search bookings..." 
            className="pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-lg w-full md:w-64 focus:ring-2 focus:ring-blue-500 outline-none"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
      </div>

      {/* Statement Generator Panel */}
      {showStatementTool && (
        <div className="bg-blue-50 border border-blue-100 p-6 rounded-xl animate-in fade-in slide-in-from-top-4 duration-300">
          <div className="flex items-center gap-3 mb-4">
            <div className="bg-blue-600 p-2 rounded-lg text-white">
              <Calendar className="w-5 h-5" />
            </div>
            <div>
              <h3 className="font-bold text-slate-900">Generate Customer Statement</h3>
              <p className="text-xs text-slate-500">Combine all operations for a specific client into one document</p>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-4 gap-4 items-end">
            <div className="space-y-1">
              <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Select Customer</label>
              <select 
                className="w-full bg-white border border-blue-200 p-2 rounded-lg outline-none focus:ring-2 focus:ring-blue-500 text-sm"
                value={statementForm.customer}
                onChange={(e) => setStatementForm({...statementForm, customer: e.target.value})}
              >
                <option value="">Choose a customer...</option>
                {uniqueCustomers.map(c => <option key={c} value={c}>{c}</option>)}
              </select>
            </div>
            <div className="space-y-1">
              <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Date From</label>
              <input 
                type="date"
                className="w-full bg-white border border-blue-200 p-2 rounded-lg outline-none focus:ring-2 focus:ring-blue-500 text-sm"
                value={statementForm.dateFrom}
                onChange={(e) => setStatementForm({...statementForm, dateFrom: e.target.value})}
              />
            </div>
            <div className="space-y-1">
              <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Date To</label>
              <input 
                type="date"
                className="w-full bg-white border border-blue-200 p-2 rounded-lg outline-none focus:ring-2 focus:ring-blue-500 text-sm"
                value={statementForm.dateTo}
                onChange={(e) => setStatementForm({...statementForm, dateTo: e.target.value})}
              />
            </div>
            <button 
              onClick={generateStatement}
              disabled={!statementForm.customer}
              className="bg-blue-600 hover:bg-blue-700 disabled:bg-slate-300 text-white font-bold py-2 rounded-lg transition-colors flex items-center justify-center gap-2"
            >
              <span>Preview Statement</span>
              <ArrowRight className="w-4 h-4" />
            </button>
          </div>
        </div>
      )}

      <div className="bg-white border border-slate-200 rounded-xl overflow-hidden shadow-sm">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-slate-50 border-b border-slate-200">
              <tr>
                <th className="px-6 py-4 text-sm font-semibold text-slate-600">Invoice No</th>
                <th className="px-6 py-4 text-sm font-semibold text-slate-600">Booking Ref</th>
                <th className="px-6 py-4 text-sm font-semibold text-slate-600">Customer</th>
                <th className="px-6 py-4 text-sm font-semibold text-slate-600">Units</th>
                <th className="px-6 py-4 text-sm font-semibold text-slate-600">Total Rate</th>
                <th className="px-6 py-4 text-sm font-semibold text-slate-600">Date</th>
                <th className="px-6 py-4 text-sm font-semibold text-slate-600">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filtered.map(inv => {
                const isUsed = usedInvoiceIds.has(inv.id);
                const textColorClass = isUsed ? 'text-red-600' : 'text-slate-700';

                return (
                  <tr key={inv.id} className={`hover:bg-slate-50 transition-colors ${isUsed ? 'bg-red-50/30' : ''}`}>
                    <td className={`px-6 py-4 font-mono text-sm font-medium ${isUsed ? 'text-red-700' : 'text-blue-600'}`}>
                      {inv.serialNumber}
                    </td>
                    <td className={`px-6 py-4 text-sm ${textColorClass}`}>{inv.bookingNo}</td>
                    <td className={`px-6 py-4 text-sm font-medium ${isUsed ? 'text-red-800' : 'text-slate-900'}`}>{inv.customer}</td>
                    <td className="px-6 py-4 text-sm">
                      <span className={`${isUsed ? 'bg-red-100 text-red-700' : 'bg-slate-100 text-slate-700'} px-2 py-0.5 rounded text-xs font-semibold`}>
                        {inv.items.length} Units
                      </span>
                    </td>
                    <td className={`px-6 py-4 text-sm font-bold ${isUsed ? 'text-red-700' : 'text-slate-900'}`}>{inv.total.toLocaleString()} EGP</td>
                    <td className={`px-6 py-4 text-sm ${isUsed ? 'text-red-400' : 'text-slate-500'}`}>{inv.date}</td>
                    <td className="px-6 py-4">
                      <button 
                        onClick={() => handlePreview(inv)}
                        className={`inline-flex items-center space-x-2 font-medium text-sm transition-colors ${isUsed ? 'text-red-600 hover:text-red-800' : 'text-blue-600 hover:text-blue-800'}`}
                      >
                        <Eye className="w-4 h-4" />
                        <span>{isUsed ? 'Regenerate' : 'Generate'}</span>
                      </button>
                    </td>
                  </tr>
                );
              })}
              {filtered.length === 0 && (
                <tr>
                  <td colSpan={7} className="px-6 py-12 text-center text-slate-500 italic">
                    No bookings found. Try importing a CSV or loading sample data.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default BookingScreen;

import React from 'react';
import { Invoice, InvoiceTheme, CompanyInfo } from '../types';

interface Props {
  invoice: Invoice;
  theme: InvoiceTheme;
  company: CompanyInfo;
}

const InvoiceRenderer: React.FC<Props> = ({ invoice, theme, company }) => {
  const getThemeBaseStyles = () => {
    switch (theme) {
      case 'dark': return "bg-white text-slate-900 font-sans";
      case 'elegant': return "bg-white text-slate-800 font-serif";
      case 'industrial': return "bg-white text-slate-900 font-mono uppercase";
      case 'bold': return "bg-white text-slate-900 font-sans";
      case 'grid': return "bg-white text-slate-900 font-mono";
      default: return "bg-white text-slate-900 font-sans";
    }
