import React, { useState, useMemo, useEffect } from 'react';
import { 
  FileText, 
  Users, 
  Settings, 
  Plus, 
  Download, 
  Printer, 
  Eye, 
  Trash2,
  FileSpreadsheet,
  Building2,
  Info
} from 'lucide-react';
import { BookingRow, CustomerSettings, CompanyInfo, Invoice, InvoiceTheme } from './types';
import { INITIAL_CSV_DATA, THEMES } from './constants';
import BookingScreen from './components/BookingScreen';
import CustomerScreen from './components/CustomerScreen';
import InfoScreen from './components/InfoScreen';
import InvoiceModal from './components/InvoiceModal';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'bookings' | 'customers' | 'info'>('bookings');
  const [bookings, setBookings] = useState<BookingRow[]>([]);
  const [customerSettings, setCustomerSettings] = useState<Record<string, CustomerSettings>>({});
  const [companyInfo, setCompanyInfo] = useState<CompanyInfo>({
    name: 'NILE FLEET',
    address: '123 Cairo Logistics Hub, Nile Delta, Egypt',
    email: 'billing@nilefleet.com',
    phone: '+20 123 456 7890',
    authName: 'Operations Manager',
    authJobTitle: 'Head of Logistics',
    authPhone: '+20 100 000 0000',
    authEmail: 'ops@nilefleet.com',
    logo: null,
    signature: null,
    watermark: null
  });

  const [selectedInvoice, setSelectedInvoice] = useState<Invoice | null>(null);
  const [selectedTheme, setSelectedTheme] = useState<InvoiceTheme>('minimal');

  const parseCSV = (csv: string): BookingRow[] => {
    const lines = csv.split('\n');
    return lines.slice(1).filter(l => l.trim()).map(line => {
      const values = line.split(',');
      return {
        Customer: values[0] || '',
        BookingNo: values[1] || '',
        UnitNumber: values[2] || '',
        PortGo: values[3] || '',
        PortGi: values[4] || '',
        Trucker: values[5] || '',
        Shipper: values[6] || '',
        Rate: parseFloat(values[7]) || 0,
        Date: values[8] || new Date().toISOString().split('T')[0]
      };
    });
  };

  // Initial Load
  useEffect(() => {
    const parsed = parseCSV(INITIAL_CSV_DATA);
    setBookings(parsed);
    updateCustomerSettings(parsed);
  }, []);

  const updateCustomerSettings = (rows: BookingRow[]) => {
    const uniqueCustomers = Array.from(new Set(rows.map(p => p.Customer)));
    setCustomerSettings(prev => {
      const next = { ...prev };
      uniqueCustomers.forEach((c, idx) => {
        if (!next[c]) {
          next[c] = {
            name: c,
            dueDateDays: 15,
            serialPrefix: 'INV-2026-',
            startingSerial: 100 + Object.keys(next).length
          };
        }
      });
      return next;
    });
  };

  // Group Bookings into Invoices
  const invoices = useMemo(() => {
    const groups: Record<string, BookingRow[]> = {};
    bookings.forEach(row => {
      if (!groups[row.BookingNo]) groups[row.BookingNo] = [];
      groups[row.BookingNo].push(row);
    });

    return Object.entries(groups).map(([bookingNo, items], index) => {
      const customerName = items[0].Customer;
      const settings = customerSettings[customerName];
      const serialNum = settings 
        ? `${settings.serialPrefix}${settings.startingSerial + index}`
        : `INV-${bookingNo}`;

      const date = new Date(items[0].Date);
      const dueDate = new Date(date);
      dueDate.setDate(date.getDate() + (settings?.dueDateDays || 15));

      return {
        id: bookingNo,
        bookingNo,
        customer: customerName,
        date: items[0].Date,
        dueDate: dueDate.toISOString().split('T')[0],
        serialNumber: serialNum,
        items,
        total: items.reduce((sum, item) => sum + item.Rate, 0)
      } as Invoice;
    });
  }, [bookings, customerSettings]);

  const handleUpdateCustomer = (name: string, settings: CustomerSettings) => {
    setCustomerSettings(prev => ({ ...prev, [name]: settings }));
  };

  const handleUpdateInfo = (info: Partial<CompanyInfo>) => {
    setCompanyInfo(prev => ({ ...prev, ...info }));
  };

  const handleImportCSV = (data: BookingRow[]) => {
    setBookings(data);
    updateCustomerSettings(data);
  };

  const handleClearAll = () => {
    if (confirm('Are you sure you want to remove all booking operations?')) {
      setBookings([]);
    }
  };

  return (
    <div className="min-h-screen flex flex-col md:flex-row">
      {/* Sidebar */}
      <nav className="w-full md:w-64 bg-slate-900 text-white p-6 space-y-8 no-print shrink-0">
        <div className="flex items-center space-x-3">
          <div className="p-2 bg-blue-600 rounded-lg">
            <Building2 className="w-6 h-6" />
          </div>
          <h1 className="text-xl font-bold tracking-tight">NILE FLEET</h1>
        </div>

        <div className="space-y-1">
          <button 
            onClick={() => setActiveTab('bookings')}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-colors ${activeTab === 'bookings' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:bg-slate-800'}`}
          >
            <FileSpreadsheet className="w-5 h-5" />
            <span className="font-medium">Bookings</span>
          </button>
          <button 
            onClick={() => setActiveTab('customers')}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-colors ${activeTab === 'customers' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:bg-slate-800'}`}
          >
            <Users className="w-5 h-5" />
            <span className="font-medium">Customers</span>
          </button>
          <button 
            onClick={() => setActiveTab('info')}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-colors ${activeTab === 'info' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:bg-slate-800'}`}
          >
            <Info className="w-5 h-5" />
            <span className="font-medium">My Info</span>
          </button>
        </div>

        <div className="pt-8 border-t border-slate-800">
          <p className="text-xs text-slate-500 uppercase tracking-wider font-semibold mb-4">Invoice Theme</p>
          <div className="grid grid-cols-1 gap-2">
            {THEMES.map(theme => (
              <button
                key={theme.id}
                onClick={() => setSelectedTheme(theme.id)}
                className={`text-sm px-3 py-1.5 rounded border transition-all text-left ${selectedTheme === theme.id ? 'border-blue-500 bg-blue-500/10 text-blue-400' : 'border-slate-700 text-slate-400 hover:border-slate-500'}`}
              >
                {theme.name}
              </button>
            ))}
          </div>
        </div>
      </nav>

      {/* Main Content */}
      <main className="flex-1 bg-slate-50 p-4 md:p-8 overflow-y-auto">
        <div className="max-w-6xl mx-auto">
          {activeTab === 'bookings' && (
            <BookingScreen 
              invoices={invoices} 
              onPreview={(inv) => setSelectedInvoice(inv)}
              onImport={handleImportCSV}
              onClearAll={handleClearAll}
              onLoadSample={() => {
                const parsed = parseCSV(INITIAL_CSV_DATA);
                handleImportCSV(parsed);
              }}
            />
          )}
          {activeTab === 'customers' && (
            <CustomerScreen 
              settings={customerSettings} 
              onUpdate={handleUpdateCustomer} 
            />
          )}
          {activeTab === 'info' && (
            <InfoScreen 
              info={companyInfo} 
              onUpdate={handleUpdateInfo} 
            />
          )}
        </div>
      </main>

      {/* Invoice Modal */}
      {selectedInvoice && (
        <InvoiceModal 
          invoice={selectedInvoice} 
          theme={selectedTheme} 
          company={companyInfo}
          onClose={() => setSelectedInvoice(null)} 
        />
      )}
    </div>
  );
};

export default App;

import React, { useRef, useState } from 'react';
import { Eye, Search, Upload, RefreshCcw, FileText, Calendar, ArrowRight, ChevronDown, ChevronUp, Download, Trash2 } from 'lucide-react';
import { Invoice, BookingRow } from '../types';
import { INITIAL_CSV_DATA } from '../constants';

interface Props {
  invoices: Invoice[];
  onPreview: (invoice: Invoice) => void;
  onImport: (data: BookingRow[]) => void;
  onClearAll: () => void;
  onLoadSample: () => void;
}

const BookingScreen: React.FC<Props> = ({ invoices, onPreview, onImport, onClearAll, onLoadSample }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [usedInvoiceIds, setUsedInvoiceIds] = useState<Set<string>>(new Set());
  const [showStatementTool, setShowStatementTool] = useState(false);
  const [statementForm, setStatementForm] = useState({
    customer: '',
    dateFrom: '',
    dateTo: ''
  });

  const fileInputRef = useRef<HTMLInputElement>(null);

  const filtered = invoices.filter(inv => 
    inv.bookingNo.toLowerCase().includes(searchTerm.toLowerCase()) ||
    inv.customer.toLowerCase().includes(searchTerm.toLowerCase()) ||
    inv.serialNumber.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const uniqueCustomers = Array.from(new Set(invoices.map(inv => inv.customer)));

  const handlePreview = (inv: Invoice) => {
    setUsedInvoiceIds(prev => new Set(prev).add(inv.id));
    onPreview(inv);
  };

  const handleDownloadSample = () => {
    const blob = new Blob([INITIAL_CSV_DATA], { type: 'text/csv' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'nile-fleet-sample-operations.csv';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const generateStatement = () => {
    if (!statementForm.customer) return;

    // Collect all raw bookings for this customer (across all grouped invoices)
    const allMatchingBookings: BookingRow[] = [];
    invoices
      .filter(inv => inv.customer === statementForm.customer)
      .forEach(inv => {
        inv.items.forEach(item => {
          const itemDate = new Date(item.Date);
          const from = statementForm.dateFrom ? new Date(statementForm.dateFrom) : null;
          const to = statementForm.dateTo ? new Date(statementForm.dateTo) : null;

          if ((!from || itemDate >= from) && (!to || itemDate <= to)) {
            allMatchingBookings.push(item);
          }
        });
      });

    if (allMatchingBookings.length === 0) {
      alert("No operations found for the selected criteria.");
      return;
    }

    const statementPeriod = `${statementForm.dateFrom || 'Start'} to ${statementForm.dateTo || 'End'}`;

    const statementInvoice: Invoice = {
      id: `statement-${statementForm.customer}-${Date.now()}`,
      bookingNo: "MULTIPLE",
      customer: statementForm.customer,
      date: new Date().toISOString().split('T')[0],
      dueDate: "On Receipt",
      serialNumber: `SOA-${Date.now().toString().slice(-6)}`,
      items: allMatchingBookings,
      total: allMatchingBookings.reduce((sum, item) => sum + item.Rate, 0),
      isStatement: true,
      period: statementPeriod
    };

    onPreview(statementInvoice);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        const text = event.target?.result as string;
        const lines = text.split('\n');
        const parsed: BookingRow[] = lines.slice(1).filter(l => l.trim()).map(line => {
          const values = line.split(',');
          return {
            Customer: values[0]?.trim() || '',
            BookingNo: values[1]?.trim() || '',
            UnitNumber: values[2]?.trim() || '',
            PortGo: values[3]?.trim() || '',
            PortGi: values[4]?.trim() || '',
            Trucker: values[5]?.trim() || '',
            Shipper: values[6]?.trim() || '',
            Rate: parseFloat(values[7]) || 0,
            Date: values[8]?.trim() || new Date().toISOString().split('T')[0]
          };
        });
        onImport(parsed);
      };
      reader.readAsText(file);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-start justify-between gap-6">
        <div className="space-y-4">
          <div>
            <h2 className="text-2xl font-bold text-slate-800">Booking Operations</h2>
            <p className="text-slate-500">View and generate invoices from your logistics operations</p>
          </div>

          <div className="flex flex-wrap gap-2">
            <button 
              onClick={() => fileInputRef.current?.click()}
              className="inline-flex items-center space-x-2 px-4 py-2 bg-blue-600 hover:bg-blue-700 text-white text-sm font-semibold rounded-lg transition-colors shadow-sm shadow-blue-500/20"
            >
              <Upload className="w-4 h-4" />
              <span>Import CSV</span>
            </button>
            <input 
              type="file" 
              ref={fileInputRef} 
              className="hidden" 
              accept=".csv" 
              onChange={handleFileChange} 
            />

            <button 
              onClick={handleDownloadSample}
              className="inline-flex items-center space-x-2 px-4 py-2 bg-white hover:bg-slate-50 text-slate-700 text-sm font-semibold rounded-lg transition-colors border border-slate-200"
            >
              <Download className="w-4 h-4" />
              <span>Download Sample CSV</span>
            </button>

            <button 
              onClick={() => setShowStatementTool(!showStatementTool)}
              className={`inline-flex items-center space-x-2 px-4 py-2 text-sm font-semibold rounded-lg transition-all border ${showStatementTool ? 'bg-blue-50 border-blue-200 text-blue-700' : 'bg-white border-slate-200 text-slate-700 hover:bg-slate-50'}`}
            >
              <FileText className="w-4 h-4" />
              <span>Statement of Account</span>
              {showStatementTool ? <ChevronUp className="w-4 h-4 ml-1" /> : <ChevronDown className="w-4 h-4 ml-1" />}
            </button>

            <button 
              onClick={onLoadSample}
              className="inline-flex items-center space-x-2 px-4 py-2 bg-slate-100 hover:bg-slate-200 text-slate-700 text-sm font-semibold rounded-lg transition-colors border border-slate-200"
