    }

    const totalSection = (
      <div className={`${totalBoxClass} shrink-0`}>
         <div className="text-left">
            <div className={`text-[9px] font-black uppercase mb-0.5 ${isDark ? 'text-blue-200' : 'text-slate-400'}`}>Total Amount Due</div>
