         </div>
         <div className="text-right">
            <div className="text-5xl font-black tabular-nums">{invoice.total.toLocaleString()}</div>
         </div>
      </div>
    );

    return (
      <div className="mt-auto flex flex-col gap-6">
        <div className="flex flex-col md:flex-row gap-6 items-start">
          <div className="flex-1 space-y-4">
             <div className={`p-4 ${isDark ? 'bg-slate-800 border-slate-700' : 'bg-slate-50 border-slate-100'} border rounded-xl`}>
                <h5 className={`text-[10px] font-black uppercase mb-2 ${isDark ? 'text-blue-400' : 'text-blue-600'}`}>Terms & Settlement</h5>
                <p className="text-[10px] leading-relaxed opacity-70">
                  Please settle this invoice by <span className="font-black underline">{invoice.dueDate}</span>. 
                  All payments should be directed to Nile Fleet accounts. Please mention document 
                  reference <span className="font-bold">{invoice.serialNumber}</span> in your transfer notes.
                </p>
             </div>

             <div className="relative pt-6">
                {company.signature && (
                  <div className="absolute -top-20 -left-4 z-10 pointer-events-none">
                    <img 
                      src={company.signature} 
                      className={`h-40 w-auto mix-blend-multiply object-contain opacity-95 -rotate-2 ${isDark ? 'brightness-200 invert grayscale' : 'grayscale'}`} 
                      alt="Signature" 
                    />
                  </div>
                )}
                <div className={`border-l-2 pl-3 relative z-0 ${isDark ? 'border-blue-500' : 'border-slate-900'}`}>
                   <p className={`text-sm font-black uppercase leading-none ${isDark ? 'text-white' : 'text-slate-900'}`}>{company.authName}</p>
                   <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mt-1">{company.authJobTitle}</p>
                   {/* "My Info" under Authorize - Address now next to Email/Phone */}
                   <div className="mt-2 text-[8px] font-bold text-slate-400 uppercase flex flex-wrap gap-x-3 items-center leading-relaxed">
                      <div className="flex items-center gap-1.5">
                        <span className="opacity-50">LOCATION:</span>
                        <span>{company.address}</span>
                      </div>
                      <div className="w-1 h-1 rounded-full bg-slate-300" />
                      <div className="flex items-center gap-1.5">
                        <span className="opacity-50">CONTACT:</span>
                        <span>{company.email} • {company.phone}</span>
                      </div>
                   </div>
                </div>
             </div>
          </div>

          <div className="w-full md:w-80 flex flex-col gap-4">
            {totalSection}
            <div className={`text-[8px] font-bold text-center uppercase tracking-[0.2em] ${isDark ? 'text-slate-600' : 'text-slate-300'}`}>
              Thank you for choosing Nile Fleet Genset
            </div>
          </div>
        </div>

        <div className={footerTaglineClass}>
          <div className={`font-black mb-0.5 ${isDark ? 'text-slate-400' : 'text-slate-900'}`}>NILE FLEET GENSET</div>
          <div className="opacity-30 font-bold text-[7px]">POWERD BY BEBITO</div>
        </div>
      </div>
    );
  };

  return (
    <div className={`invoice-container relative shadow-none transition-all duration-500 overflow-hidden ${getThemeBaseStyles()} ${theme === 'grid' ? 'bg-dot-grid' : ''}`}>
      {/* Watermark */}
      {company.watermark && (
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 opacity-[0.04] pointer-events-none rotate-45 scale-150">
          <img src={company.watermark} className={`w-[120mm] h-auto grayscale ${isDark ? 'invert' : ''}`} />
        </div>
      )}

      {renderHeader()}
      {renderBillTo()}
      <div className="flex-1 overflow-hidden">
        {renderTable()}
      </div>
      {renderFooter()}

      {/* Decorative Stamp for specific themes */}
      {(theme === 'industrial' || theme === 'ledger-pro' || theme === 'dark') && (
        <div className={`absolute top-12 right-12 border-2 rounded-full w-20 h-20 flex items-center justify-center -rotate-12 pointer-events-none ${isDark ? 'border-blue-500/10' : 'border-red-500/10'}`}>
           <div className={`text-[7px] font-black text-center uppercase ${isDark ? 'text-blue-500/10' : 'text-red-500/10'}`}>
             APPROVED<br/>NILE FLEET<br/>GENSET POWER
           </div>
        </div>
      )}

      {theme === 'grid' && (
        <div className="absolute inset-0 pointer-events-none opacity-[0.03]" 
             style={{ backgroundImage: 'radial-gradient(#000 0.5px, transparent 0.5px)', backgroundSize: '20px 20px' }} />
      )}
    </div>
  );
};

