                     <span className="text-slate-600">{company.address}</span>
                   </div>
                   <div className="flex items-center gap-2">
                     <span className="opacity-50 font-black">NET:</span>
                     <span className="text-slate-600">{company.email} • {company.phone}</span>
                   </div>
