              <div className="relative mt-8">
                <img 
                  src={company.signature} 
                  className={`h-36 w-auto mix-blend-multiply object-contain opacity-95 transition-transform drop-shadow-sm ${isDark ? 'brightness-200 invert grayscale' : 'grayscale'}`} 
                  alt="Signature" 
                />
                <div className="absolute -bottom-1 left-1/2 -translate-x-1/2 w-4/5 h-0.5 bg-slate-900/5 rounded-full" />
              </div>
            )}
