                </div>
             </div>
             <div className="flex justify-between items-end border-t border-slate-100 pt-8">
                {authAndSignature}
                <div className="text-right text-[8px] font-black opacity-20 uppercase tracking-[1em] mb-1">Registry #NF9928</div>
             </div>
             {taglineSection}
          </div>
